const dados = $items();

// Função formatadora
const format = (val) => new Intl.NumberFormat('pt-BR', {
  style: 'currency',
  currency: 'BRL',
  minimumFractionDigits: 2
}).format(val ?? 0);

// Função para agrupar por filial dinamicamente com fallback de campos
function agruparPorFilial(lista, chavesCampoValor, chaveInterna) {
  const grupos = {};
  lista
    .filter(item => item.json[chaveInterna])
    .forEach(item => {
      const obj = item.json[chaveInterna];
      const filial = obj.fil_descricao || "❌ Filial não informada";

      // Tenta pegar o primeiro campo válido entre os disponíveis
      let valor = 0;
      for (const campo of chavesCampoValor) {
        if (obj[campo] !== undefined) {
          valor = obj[campo];
          break;
        }
      }

      if (!grupos[filial]) {
        grupos[filial] = { filial, valor: 0 };
      }
      grupos[filial].valor += valor;
    });
  return Object.values(grupos).filter(item => item.valor > 0); // não inclui se valor for zero
}

// Agrupamentos com fallback de campo
const inssDetalhado = agruparPorFilial(dados, ['Af_valor_af', 'Af_valor_af_INSS'], 'inss');
const prefDetalhado = agruparPorFilial(dados, ['Af_valor_af'], 'prefsp');
const govDetalhado = agruparPorFilial(dados, ['Af_valor_af'], 'govsp');
const caldasDetalhado = agruparPorFilial(dados, ['Af_valor_af', 'Receita'], 'prefcaldasnovas');

// Totais gerais
const total = dados.find(item => item.json.empresaTotal)?.json.empresaTotal || {};
const totalEmpresas = dados
  .filter(item => item.json.prodEmpresa)
  .map(item => item.json.prodEmpresa);

// Data atual
const dataHoje = new Date().toLocaleDateString('pt-BR');

// Função para montar texto de cada grupo
function montarEmpresa(nome, dados) {
  if (!dados || dados.length === 0) return '';
  let texto = `🏢 ${nome}\n`;
  dados.forEach(item => {
    texto += `   • ${item.filial}: ${format(item.valor)}\n`;
  });
  return texto + '\n';
}

// Receita geral formatada linha a linha
const receitaGeralTexto = totalEmpresas.map(emp => 
  `🏢 ${emp.fil_descricao || "❌ Filial não informada"}\n` +
  `📊 Produção Total: ${format(emp.ProducaoTotal)}\n` +
  `💰 Receita: ${format(emp.Receita)}\n` +
  `📈 Percentual Receita: ${emp.ReceitaEmpresaPorcentTotal}%\n`
).join('\n');

// Mensagem final
const mensagem = 
`Boa tarde, HOJE (${dataHoje})

Finalizamos o dia com:
📊 Produção Total: ${format(total.Producao)}
💰 Receita: ${format(total.Receita)}
📈 Percentual Receita: ${(total.PorcentTotal ?? 0).toFixed(2)}%

📌 Detalhamento por empresa:

${montarEmpresa("INSS", inssDetalhado)}
${montarEmpresa("PREF SP", prefDetalhado)}
${montarEmpresa("GOV SP", govDetalhado)}
${montarEmpresa("PREF CALDAS NOVAS", caldasDetalhado)}
🔍 Receita Geral por Filial:
${receitaGeralTexto}
`;

// Lista de contatos para disparo
const contatos = [
  { nome: "Felipe", numero: "5519960001690" },
  { nome: "Denis", numero: "5519981353889" },
  { nome: "Daniel", numero: "5519996109532" },
  { nome: "Jessica", numero: "5519999331273" }
];

// Retorna uma mensagem para cada contato
return contatos.map(contato => ({
  json: {
    nome: contato.nome,
    numero: contato.numero,
    message: mensagem
  }
}));

